export type Direction = 'left' | 'right' | 'up' | 'down'

export interface MoveResult {
  board: number[]
  scoreGained: number
  moved: boolean
}

export interface GameState {
  board: number[]
  score: number
  status: string
  won: boolean
  gameOver: boolean
}

export const BOARD_SIZE = 4
export const CELL_COUNT = BOARD_SIZE * BOARD_SIZE

const emptyBoard = (): number[] => Array(CELL_COUNT).fill(0)

export const createEmptyBoard = emptyBoard

export function getCell(board: number[], row: number, col: number): number {
  return board[row * BOARD_SIZE + col]
}

export function setCell(board: number[], row: number, col: number, value: number): void {
  board[row * BOARD_SIZE + col] = value
}

export function getEmptyIndices(board: number[]): number[] {
  return board
    .map((value, index) => (value === 0 ? index : -1))
    .filter((index) => index !== -1)
}

export function spawnRandomTile(board: number[], random = Math.random): number[] {
  const emptyIndices = getEmptyIndices(board)
  if (emptyIndices.length === 0) {
    return [...board]
  }

  const index = emptyIndices[Math.floor(random() * emptyIndices.length)]
  const value = random() < 0.9 ? 2 : 4
  const next = [...board]
  next[index] = value
  return next
}

function slideAndMerge(line: number[]): { line: number[]; scoreGained: number; moved: boolean } {
  const filtered = line.filter((value) => value !== 0)
  const merged: number[] = []
  let scoreGained = 0

  for (let i = 0; i < filtered.length; i += 1) {
    if (filtered[i] !== 0 && filtered[i] === filtered[i + 1]) {
      const value = filtered[i] * 2
      merged.push(value)
      scoreGained += value
      i += 1
    } else {
      merged.push(filtered[i])
    }
  }

  while (merged.length < BOARD_SIZE) {
    merged.push(0)
  }

  const moved = merged.some((value, index) => value !== line[index])
  return { line: merged, scoreGained, moved }
}

function reverse(line: number[]): number[] {
  return [...line].reverse()
}

function getRow(board: number[], row: number): number[] {
  return Array.from({ length: BOARD_SIZE }, (_, col) => getCell(board, row, col))
}

function setRow(board: number[], row: number, values: number[]): void {
  values.forEach((value, col) => setCell(board, row, col, value))
}

function getCol(board: number[], col: number): number[] {
  return Array.from({ length: BOARD_SIZE }, (_, row) => getCell(board, row, col))
}

function setCol(board: number[], col: number, values: number[]): void {
  values.forEach((value, row) => setCell(board, row, col, value))
}

export function moveBoard(board: number[], direction: Direction): MoveResult {
  const next = [...board]
  let scoreGained = 0
  let moved = false

  for (let index = 0; index < BOARD_SIZE; index += 1) {
    const original = direction === 'left' || direction === 'right' ? getRow(board, index) : getCol(board, index)
    const working = direction === 'right' || direction === 'down' ? reverse(original) : original
    const result = slideAndMerge(working)
    const restored = direction === 'right' || direction === 'down' ? reverse(result.line) : result.line

    if (direction === 'left' || direction === 'right') {
      setRow(next, index, restored)
    } else {
      setCol(next, index, restored)
    }

    scoreGained += result.scoreGained
    moved = moved || result.moved
  }

  return { board: next, scoreGained, moved }
}

export function hasWinningTile(board: number[]): boolean {
  return board.some((value) => value >= 2048)
}

export function canMove(board: number[]): boolean {
  if (getEmptyIndices(board).length > 0) {
    return true
  }

  for (let row = 0; row < BOARD_SIZE; row += 1) {
    for (let col = 0; col < BOARD_SIZE; col += 1) {
      const value = getCell(board, row, col)
      if (col + 1 < BOARD_SIZE && value === getCell(board, row, col + 1)) {
        return true
      }
      if (row + 1 < BOARD_SIZE && value === getCell(board, row + 1, col)) {
        return true
      }
    }
  }

  return false
}

export function getStatus(won: boolean, gameOver: boolean): string {
  if (gameOver) return 'Game over'
  if (won) return 'You win!'
  return 'Keep going'
}

export function createInitialGame(random = Math.random): GameState {
  let board = emptyBoard()
  board = spawnRandomTile(board, random)
  board = spawnRandomTile(board, random)
  const won = hasWinningTile(board)
  const gameOver = !canMove(board)
  return {
    board,
    score: 0,
    won,
    gameOver,
    status: getStatus(won, gameOver),
  }
}

export function applyMove(state: GameState, direction: Direction, random = Math.random): GameState {
  if (state.gameOver) {
    return state
  }

  const moved = moveBoard(state.board, direction)
  if (!moved.moved) {
    return state
  }

  const board = spawnRandomTile(moved.board, random)
  const score = state.score + moved.scoreGained
  const won = state.won || hasWinningTile(board)
  const gameOver = !canMove(board)

  return {
    board,
    score,
    won,
    gameOver,
    status: getStatus(won, gameOver),
  }
}

export function keyToDirection(key: string): Direction | null {
  switch (key) {
    case 'ArrowLeft':
    case 'a':
    case 'A':
      return 'left'
    case 'ArrowRight':
    case 'd':
    case 'D':
      return 'right'
    case 'ArrowUp':
    case 'w':
    case 'W':
      return 'up'
    case 'ArrowDown':
    case 's':
    case 'S':
      return 'down'
    default:
      return null
  }
}

import { useEffect, useState } from 'react'
import './App.css'
import { applyMove, BOARD_SIZE, CELL_COUNT, createInitialGame, keyToDirection } from './game'

function App() {
  const [game, setGame] = useState(() => createInitialGame())

  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      const direction = keyToDirection(event.key)
      if (!direction) return
      event.preventDefault()
      setGame((current) => applyMove(current, direction))
    }

    window.addEventListener('keydown', onKeyDown)
    return () => window.removeEventListener('keydown', onKeyDown)
  }, [])

  return (
    <main className="app">
      <section className="game-shell" aria-label="2048 game">
        <header className="topbar">
          <div>
            <h1>2048</h1>
            <p className="subtitle">Use arrow keys or WASD to combine tiles.</p>
          </div>
          <div className="score-panel">
            <span>Score</span>
            <strong data-testid="score">{game.score}</strong>
          </div>
        </header>

        <div className="controls">
          <p data-testid="status" className={`status ${game.gameOver ? 'lost' : game.won ? 'won' : ''}`}>
            {game.status}
          </p>
          <button data-testid="restart" onClick={() => setGame(createInitialGame())}>
            New Game
          </button>
        </div>

        <div
          className="board"
          data-testid="board"
          role="grid"
          aria-label="2048 board"
          aria-rowcount={BOARD_SIZE}
          aria-colcount={BOARD_SIZE}
        >
          {Array.from({ length: CELL_COUNT }, (_, index) => {
            const value = game.board[index]
            return (
              <div
                key={index}
                role="gridcell"
                className={`cell value-${value || 0}`}
                aria-label={value ? `Tile ${value}` : 'Empty cell'}
              >
                {value || ''}
              </div>
            )
          })}
        </div>
      </section>
    </main>
  )
}

export default App

